import { Component, inject, signal } from '@angular/core';
import { RouterLink } from '@angular/router';
import { FormsModule } from '@angular/forms';
import { NgClass } from '@angular/common';
import { environment } from '../../../environments/environment';
import { ToastService } from 'src/app/shared/components/toast/toast.service';
import { CartService } from './Cart.service';
import { FormaPagamento } from '../payment/Payment.model';
import { PaymentService } from '../payment/Payment.service';
import { BrlPipe } from 'src/app/shared/pipes/brl.pipe';
import { GiftService } from '../gifts/gift.service';

@Component({
  selector: 'app-cart',
  standalone: true,
  imports: [RouterLink, FormsModule, NgClass, BrlPipe],
  templateUrl: './card.component.html',,
  styleUrls: ['./card.component.scss'],
})
export class CartComponent {
  cart         = inject(CartService);
  private contribuicaoSvc = inject(PaymentService);
  private presenteSvc     = inject(GiftService);
  private toastSvc        = inject(ToastService);

  readonly pixKey  = environment.pixKey;
  readonly pixName = environment.pixName;

  nome          = signal('');
  mensagem      = signal('');
  pagamento     = signal<FormaPagamento>('PIX');
  cardNumber    = signal('');
  cardExpiry    = signal('');
  cardCvv       = signal('');
  cardName      = signal('');
  submitting    = signal(false);

  setPagamento(p: FormaPagamento): void { this.pagamento.set(p); }

  remove(id: number): void { this.cart.remove(id); }

  async finalizar(): Promise<void> {
    if (!this.nome().trim()) {
      this.toastSvc.error('Por favor, informe seu nome 😊');
      return;
    }
    if (this.cart.count() === 0) {
      this.toastSvc.error('Seu carrinho está vazio!');
      return;
    }

    this.submitting.set(true);

    this.contribuicaoSvc.registrar({
      nomeDoador:     this.nome().trim(),
      mensagem:       this.mensagem().trim() || undefined,
      formaPagamento: this.pagamento(),
      itens:          this.cart.items().map(i => ({ presenteId: i.presente.id })),
    }).subscribe({
      next: () => {
        // mark as reserved
        this.cart.items().forEach(i => this.presenteSvc.marcarReservado(i.presente.id));
        this.cart.clear();
        this.submitting.set(false);
        this.nome.set('');
        this.mensagem.set('');
        this.toastSvc.success(`Obrigado, ${this.nome() || 'amigo(a)'}! Seu presente chegou ao nosso coração 💜`);
      },
      error: () => {
        this.submitting.set(false);
        this.toastSvc.error('Ocorreu um erro. Tente novamente.');
      },
    });
  }

  formatCard(event: Event): void {
    const input = event.target as HTMLInputElement;
    let value = input.value.replace(/\D/g, '');
    value = value.match(/.{1,4}/g)?.join(' ') ?? value;
    this.cardNumber.set(value);
    input.value = value;
  }

  formatExpiry(event: Event): void {
    const input = event.target as HTMLInputElement;
    let value = input.value.replace(/\D/g, '');
    if (value.length >= 2) value = value.slice(0, 2) + '/' + value.slice(2, 4);
    this.cardExpiry.set(value);
    input.value = value;
  }
}
